static float Sel(float t, float c0, float c1, float c2, float c3, float c4)
{
    if (t < 0.24f) return Lerp(c0, c1, SmoothStep(0.02f, 0.24f, t));
    if (t < 0.5f) return Lerp(c1, c2, SmoothStep(0.24f, 0.5f, t));
    if (t < 0.78f) return Lerp(c2, c3, SmoothStep(0.5f, 0.78f, t));
    if (t < 0.92f) return Lerp(c3, c4, SmoothStep(0.78f, 0.92f, t));
    return Lerp(c3, c4, SmoothStep(0.92f, 1f, t));
}

var size = context.TileSize;
var seed = GetInt(parameters, "seed", 42);
var variation = GetFloat(parameters, "colorVariation", 0.4f);
var patchiness = GetFloat(parameters, "patchStrength", 0.3f);
var grassType = GetChoice(parameters, "grassType", "StandardGrass");

// Grass palette (0..1 floats): Shadow, Dark, Mid, Light, Highlight
float sR, sG, sB, dR, dG, dB, mR, mG, mB, lR, lG, lB, hR, hG, hB;
float baseTone;
float coolR, coolG, coolB, warmR, warmG, warmB, lushR, lushG, lushB;
float macroFreq, meadowFreq, colorRegionFreq, accentRegionFreq;
float patchBlendVal, checkerStrength, hlMix, shMix;
float warmStr, coolStr, lushStr;

if (grassType == "GrassB")
{
    sR=60f/255f; sG=102f/255f; sB=52f/255f;
    dR=88f/255f; dG=132f/255f; dB=66f/255f;
    mR=118f/255f; mG=158f/255f; mB=82f/255f;
    lR=154f/255f; lG=186f/255f; lB=106f/255f;
    hR=202f/255f; hG=220f/255f; hB=146f/255f;
    baseTone=0.62f;
    coolR=82f/255f; coolG=138f/255f; coolB=96f/255f;
    warmR=172f/255f; warmG=164f/255f; warmB=92f/255f;
    lushR=114f/255f; lushG=176f/255f; lushB=92f/255f;
    macroFreq=1.1f; meadowFreq=1.75f; colorRegionFreq=0.72f; accentRegionFreq=1.55f;
    patchBlendVal=0.24f; checkerStrength=0.012f; hlMix=0.44f; shMix=0.18f;
    warmStr=0.28f; coolStr=0.22f; lushStr=0.24f;
}
else if (grassType == "ForestGrass")
{
    sR=30f/255f; sG=54f/255f; sB=36f/255f;
    dR=42f/255f; dG=76f/255f; dB=46f/255f;
    mR=58f/255f; mG=106f/255f; mB=62f/255f;
    lR=82f/255f; lG=138f/255f; lB=82f/255f;
    hR=118f/255f; hG=176f/255f; hB=108f/255f;
    baseTone=0.56f;
    coolR=42f/255f; coolG=88f/255f; coolB=66f/255f;
    warmR=90f/255f; warmG=124f/255f; warmB=72f/255f;
    lushR=64f/255f; lushG=132f/255f; lushB=74f/255f;
    macroFreq=1.35f; meadowFreq=2.45f; colorRegionFreq=0.8f; accentRegionFreq=1.9f;
    patchBlendVal=0.28f; checkerStrength=0.009f; hlMix=0.38f; shMix=0.24f;
    warmStr=0.16f; coolStr=0.24f; lushStr=0.2f;
}
else
{
    sR=40f/255f; sG=94f/255f; sB=52f/255f;
    dR=64f/255f; dG=126f/255f; dB=66f/255f;
    mR=92f/255f; mG=160f/255f; mB=82f/255f;
    lR=132f/255f; lG=194f/255f; lB=108f/255f;
    hR=188f/255f; hG=228f/255f; hB=144f/255f;
    baseTone=0.68f;
    coolR=70f/255f; coolG=142f/255f; coolB=94f/255f;
    warmR=176f/255f; warmG=170f/255f; warmB=96f/255f;
    lushR=96f/255f; lushG=188f/255f; lushB=88f/255f;
    macroFreq=1.05f; meadowFreq=1.95f; colorRegionFreq=0.68f; accentRegionFreq=1.48f;
    patchBlendVal=0.2f; checkerStrength=0.014f; hlMix=0.48f; shMix=0.16f;
    warmStr=0.26f; coolStr=0.18f; lushStr=0.28f;
}

var variationBlend = 0.04f + variation * 0.96f;

var result = new PixelBuffer(size, size);
result.ParallelForEachPixel((x, y) =>
{
    var macro = TileableFractalNoise(x * macroFreq / (float)size * 6.2832f, y * macroFreq / (float)size * 6.2832f, Math.Max(2, (int)((float)size * macroFreq / 6.2832f)), 2, 0.55f, 2f, seed);
    var meadow = TileableFractalNoise(x * meadowFreq / (float)size * 6.2832f, y * meadowFreq / (float)size * 6.2832f, Math.Max(2, (int)((float)size * meadowFreq / 6.2832f)), 1, 0.5f, 2f, seed + 17);
    var patchCell = Math.Max(2, size / 8);
    var patchPeriod = Math.Max(1, size / patchCell);
    var patch = TileableValueNoise((float)x / patchCell, (float)y / patchCell, patchPeriod, seed + 31);
    var broadColor = TileableFractalNoise(x * colorRegionFreq * 0.58f / (float)size * 6.2832f, y * colorRegionFreq * 0.58f / (float)size * 6.2832f, Math.Max(2, (int)((float)size * colorRegionFreq * 0.58f / 6.2832f)), 2, 0.56f, 1.9f, seed + 97);
    var mediumColor = TileableFractalNoise(x * colorRegionFreq / (float)size * 6.2832f, y * colorRegionFreq / (float)size * 6.2832f, Math.Max(2, (int)((float)size * colorRegionFreq / 6.2832f)), 2, 0.52f, 2f, seed + 109);
    var colorRegion = Lerp(broadColor, mediumColor, 0.3f + variation * 0.18f);
    var accentRegion = Lerp(colorRegion, TileableFractalNoise(x * accentRegionFreq / (float)size * 6.2832f, y * accentRegionFreq / (float)size * 6.2832f, Math.Max(2, (int)((float)size * accentRegionFreq / 6.2832f)), 2, 0.58f, 2.2f, seed + 131), 0.26f + variation * 0.16f);
    var checker = ((x + y) & 1) == 0 ? -checkerStrength : checkerStrength;

    var tone = macro * 0.5f + meadow * 0.22f + patch * (0.28f + variation * 0.08f);
    tone = Lerp(tone, patch, (patchBlendVal + patchiness * 0.18f + variation * 0.05f) * variationBlend);

    if (grassType == "ForestGrass")
    {
        var canopy = TileableFractalNoise(x * 1.15f / (float)size * 6.2832f, y * 1.15f / (float)size * 6.2832f, Math.Max(2, (int)((float)size * 1.15f / 6.2832f)), 2, 0.55f, 2f, seed + 101);
        tone = Lerp(tone, canopy * 0.68f, 0.28f * variationBlend);
    }
    else if (grassType == "GrassB")
    {
        tone = Lerp(tone, patch, 0.08f * variationBlend);
    }

    tone = Lerp(baseTone, tone, variationBlend);
    tone = Math.Clamp(tone + checker * (0.18f + variation * 0.46f), 0f, 1f);

    var r = Sel(tone, sR, dR, mR, lR, hR);
    var g = Sel(tone, sG, dG, mG, lG, hG);
    var b = Sel(tone, sB, dB, mB, lB, hB);

    // Color variation
    if (variation > 0.01f)
    {
        var varStr = variation * variation;
        var warmBias = Math.Clamp((colorRegion - 0.5f) * 1.7f + (accentRegion - 0.5f) * 0.35f, -1f, 1f);
        var coolBias = Math.Clamp((0.5f - colorRegion) * 1.55f + (0.58f - accentRegion) * 0.22f, -1f, 1f);
        var lushBias = Math.Clamp((accentRegion - 0.5f) * 1.6f - warmBias * 0.22f, -1f, 1f);

        var warmMask = SmoothStep(0.1f, 0.78f, warmBias);
        var coolMask = SmoothStep(0.12f, 0.8f, coolBias);
        var lushMask = SmoothStep(0.08f, 0.74f, lushBias) * (1f - tone * 0.24f);

        var wb = varStr * warmStr * warmMask * (0.55f + (1f - tone) * 0.45f);
        var cb = varStr * coolStr * coolMask * (0.45f + tone * 0.35f);
        var lb = variation * lushStr * lushMask * (0.4f + tone * 0.35f);

        r = Lerp(r, warmR, wb);
        g = Lerp(g, warmG, wb);
        b = Lerp(b, warmB, wb);
        r = Lerp(r, coolR, cb * (1f - wb * 0.45f));
        g = Lerp(g, coolG, cb * (1f - wb * 0.45f));
        b = Lerp(b, coolB, cb * (1f - wb * 0.45f));
        r = Lerp(r, lushR, lb * (1f - wb * 0.35f));
        g = Lerp(g, lushG, lb * (1f - wb * 0.35f));
        b = Lerp(b, lushB, lb * (1f - wb * 0.35f));

        var localContrast = (accentRegion - 0.5f) * variation * 0.04f;
        if (localContrast > 0f)
        {
            r = Lerp(r, hR, localContrast);
            g = Lerp(g, hG, localContrast);
            b = Lerp(b, hB, localContrast);
        }
        else
        {
            var nc = -localContrast;
            r = Lerp(r, sR, nc);
            g = Lerp(g, sG, nc);
            b = Lerp(b, sB, nc);
        }
    }

    result.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return result;
